var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"딸꾹.","JPN":"ひくっ。","ENG":"*Hic*","TWN":"嗝嗝。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어라? 벌써 다 마셨나?","JPN":"あれ？　もう飲み切っちゃった？","ENG":"Hmm? It's gone already?","TWN":"嗯？都喝完啦？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"말도 안 돼…….","JPN":"バカな……","ENG":"Impossible...","TWN":"怎麼可能……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"술을 연료로 동작하는 메커니즘인데, 인간에게 흡수력이 밀린다고?","JPN":"酒を燃料として作動するメカニズムなのに、人間の吸収力に負けてるだなんて？","ENG":"It was built to use booze as fuel... How can it be beaten by a human?!","TWN":"它的運作機制是以酒作為燃料，竟然會喝輸人類？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ff3636>경고. 경고. 동력원 과다 공급.</color>","JPN":"<color=#ff3636>警告。警告。動力源過剰供給。</color>","ENG":"<color=#ff3636>Warning. Warning. Power overload.</color>","TWN":"<color=#ff3636>警告，警告，動能超載。</color>"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MODER_BOSS_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L13_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"내, 내 걸작이 지다니!","JPN":"わ、私の傑作が負けたなんて！","ENG":"M-my masterpiece!!","TWN":"我…我的傑作竟然會輸！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"우, 우승자가 탄생했습니다! 실례지만 성함이?","JPN":"ゆ、優勝者が誕生しました！　失礼ですが、お名前は？","ENG":"W-we have a winner! Um, excuse me, but what's your name?","TWN":"贏…贏家出爐啦！不好意思，請問怎麼稱呼？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"딸꾹… 사랑의 조언가, 그레모리야.","JPN":"ひくっ……恋のカウンセラー、グレモリーよ。","ENG":"*Hic* Gremory, the Love Adviser.","TWN":"嗝嗝…我是愛情專家 葛茉莉。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MC_HAVEN_NULL_NULL","text":{"KOREA":"그레모리 씨의 승리입니다!","JPN":"グレモリーさんの勝利です！","ENG":"Ms. Gremory is the winner!","TWN":"獲勝的是葛茉莉小姐！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MC_HAVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"정말 연약한 로봇이었어. 딸꾹.","JPN":"本当に弱いロボットだったわ。ひっく。","ENG":"What a weak robot. *Hic*","TWN":"這機器人超弱的，嗝～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"……졌어. 깔끔하게 인정할게. 나도 아직 한참 멀었네.","JPN":"……負けたわ。潔く認めるよ。私もまだまだってことね。","ENG":"I lost... I'll admit it. Guess I still have a long way to go.","TWN":"……我認輸！看來我還差得遠呢。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"궁금한 게 있어. 저 아이들이 뭘 준다고 했길래 대신 대결에 나온 거지?","JPN":"気になることがあるんだけど。あの子たちから何をもらう条件で代わりに対決に出たの？","ENG":"Lemme ask you a question. What did those kids promise you in exchange?","TWN":"我有個疑問，她是用什麼東西收買你，讓你願意來代打？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"왜 이래, 언니~ 그야 당연히 술이지~","JPN":"何よ、お姉ちゃん～そりゃあ、お酒に決まってるじゃないの～","ENG":"C'mon, sis! Booze, of course!","TWN":"怎麼這麼說呢，姊姊～當然就是酒囉～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"해냈어! 시그마! 네 덕분이야!","JPN":"やった！　シグマ！　あなたのおかげだよ！","ENG":"We did it! Sigma! It's all thanks to you!","TWN":"成功咧！西格瑪！都是你的功勞！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"몸이 깃털처럼 가벼워. 헹가래하기도 쉽네.","JPN":"身体が羽みたに軽い。胴上げしやすいね。","ENG":"You're light as a feather. It's so easy to hoist you.","TWN":"你輕得像羽毛一樣，應該可以把你拋起來吧。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아하하하하! 시그마 해적단 승리!","JPN":"あはははは！　シグマ海賊団の勝利！","ENG":"Ah hah hah hah hah! The Sigma Pirates win!","TWN":"哈哈哈哈哈！西格瑪海盜團獲勝！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그리고…… 약간의 재미였으려나?","JPN":"それに……ちょっとした楽しさかしらね。","ENG":"And... maybe get some fun out of it?","TWN":"還有就是……一些樂趣？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"재미?","JPN":"楽しさ？","ENG":"Fun?","TWN":"樂趣？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래, 보기 재밌잖아. 순진한 아이들이 세상을 헤쳐 나가는 모습이.","JPN":"そう、見てて楽しいじゃない。純粋な子どもたちが世界を切り開いていく姿が。","ENG":"Yeah, look at those kids fighting against the world. Isn't it fun to watch?","TWN":"是啊，不覺得很有趣嗎？小蝦米戰勝大鯨魚的樣子。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아줌마, 정말 고마워! 다음에 꼭 우리 회사 놀러와!","JPN":"おばさん、本当にありがとう！　今度絶対会社に遊びに来てね！","ENG":"Gremory! Thanks a lot! Come by the office next time!","TWN":"阿姨，真的很謝謝你！下次再來我們公司玩喔！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"글쎄, 갈 수 있으려나 모르겠다. 얘.","JPN":"さあ、行けるかしらね。","ENG":"I dunno if I'll be able to, kid.","TWN":"這個嘛，不知道去不去得成呢。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"어? 왜? 관리부장이랑 싸웠어? 내가 화해시켜 줄까?","JPN":"え？　なんで？　管理部長とケンカしたの？　私が仲直りさせてあげようか？","ENG":"Oh? Why not? Did you fight with Hana? Do you want me to help you make up with her?","TWN":"嗯？為什麼？你和管理部長吵架喔？要我當你們的和事佬嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"이유는 나중에 실장님 가족들에게 직접 물어 봐.","JPN":"理由はあとで室長の家族に直接聞いてみなさい。","ENG":"You can ask your family why later.","TWN":"理由之後你再直接去問家人吧。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"물론 오늘의 모험을 끝낸 다음에. 마침 무척이나 재미있어 보이는 친구도 사귀었네.","JPN":"もちろん今日の冒険が終わったらね。とても面白そうな友達もできたみたいだし。","ENG":"But only after you’re done with your adventure, of course. Plus, I see you've made such an interesting friend along the way.","TWN":"不過當然是等今天的冒險結束後，你感覺交到非常有趣的朋友呢。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응. 얘는 루루야. 우리 해적단의 조리장이지.","JPN":"うん。この子はルルだよ。私の海賊団の調理長なんだ。","ENG":"Yes. She's Lulu! Our crew's chef.","TWN":"嗯，她是露露，是我們海盜團的料理長。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"……악마.","JPN":"……悪魔。","ENG":"...Devil.","TWN":"……魔鬼。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗. 서로 비슷한 처지에 왜 그래, 요괴님.","JPN":"ふふっ。お互い似たような立場でしょ、妖怪さん。","ENG":"Fu fu. You and I are in a similar situation, little Ms. Monster.","TWN":"呵呵，我們彼此彼此吧，妖怪。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"동지가 그 꼴이 났는데 사람에게 정 붙이면 안 된다는 걸 여태 못 깨달았어?","JPN":"仲間があんなになっちゃったのに、人に情を寄せちゃダメってことにまだ気付いてないのかしら？","ENG":"You still haven’t realized you shouldn’t get attached to humans after seeing what happened to your friend?","TWN":"看到你的同伴落得那般下場，應該就知道不能對人類放感情吧？你還沒認清事實嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"루루, 아줌마랑 아는 사이였어?","JPN":"ルル、おばさんと知り合いだったの？","ENG":"Lulu, do you know Gremory?","TWN":"露露，你認識阿姨媽？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"아니. 저런 아줌마 몰라.","JPN":"ううん。あんなおばさん知らない。","ENG":"No. I don't know her.","TWN":"不認識，我才不認識這個阿姨。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"푸훗. 그럼 건투를 빌게, 코핀 컴퍼니 실장님.","JPN":"ぷっ。それじゃあ、健闘を祈るわね。コフィンカンパニーの室長さん。","ENG":"Fuu fuu. Anyway, good luck, Ms. Coffin Company Executive.","TWN":"噗哈，那就祝你們好運囉，科芬公司室長。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"실은 선약이 있었거든. 늦었다고 한 소리 듣겠어.","JPN":"実は先約があったの。遅くなったって怒られちゃう。","ENG":"I'm actually meeting someone here. I might get nagged for being late.","TWN":"不瞞你說，我還有約，都已經遲到囉。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"응! 잘 가! 술고래 아줌마! 오늘 일은 잊지 않을게!","JPN":"うん！　バイバイ！　のんべえのおばさん！　今日のこと忘れないね！","ENG":"Okay! Bye, Ms. Hard Drinker! I won't forget what you did for us today!","TWN":"喔！酒鬼阿姨拜拜！今天的事我不會忘記的！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"으윽, 머리가 깨질 것 같아…….","JPN":"ううっ、頭が割れそう……","ENG":"Ngh... My head... It's pounding like crazy...","TWN":"呃呃，我整個頭痛欲裂……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"참아야 해, 글린다. 숙취에는 약이 없어.","JPN":"我慢して、グリンダ。二日酔いに効く薬はないよ。","ENG":"You have to just push through, Glinda. There's no cure for a hangover.","TWN":"格琳達，你忍耐一下，宿醉是沒有解藥的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"자, 받아. VIP 카드야.","JPN":"はい。VIPカード。","ENG":"Take it. It's the VIP card.","TWN":"拿去吧，VIP卡。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"표정이 왜 그래? 그렇게 기뻐 보이지 않는데?","JPN":"なんだか表情が暗いね？　嬉しくないの？","ENG":"Why are you looking at me like that? Aren't you happy to get it?","TWN":"那是什麼表情？怎麼一點喜悅之情都沒有？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"나랑 수아가 차고 있는 장비를 당신이 만들었다고 했지? 어떻게 된 거야?","JPN":"私とコトリが着けてる装備をあんたが作ったって言ったよね。どういうこと？","ENG":"The equipment Skia and I are wearing. You said you made them, right? How did that happen?","TWN":"你說我和蘇亞身上的裝備是你做的嗎？這是怎麼回事？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"아아, 그거?","JPN":"ああ、それ？","ENG":"Oh, that?","TWN":"喔喔～那個喔？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"난 원래 난민지구 출신이거든. 그 때는 하루하루 먹고 살기도 바빴지.","JPN":"私は元々難民地区の出身でさ。当時は日々生き延びるのも精一杯だったんだ。","ENG":"I'm actually from the refugee district. Back then, I was busy making ends meet.","TWN":"我來自難民區，那時候每天光是要填飽肚子就已經分身乏術。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"한 푼 두 푼 모아 만든 내 첫 작품을 동네 불량배 놈들이 빼앗아 고철로 갖다 판 날이었어.","JPN":"ちょっとずつお金を貯めて作った私の初作品を、街の不良が奪っていってくず鉄として売り出した日だったな。","ENG":"Some thugs stole my first work that I had saved every penny to make. Then they sold it for scraps.","TWN":"我用一點一點辛苦存下來的錢做出第一個傑作，結果卻被附近的小混混搶走。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"놈들에게 얻어맞고 쓰러져 있던 내게, 헤이븐 형님이 손을 내밀어 주셨지.","JPN":"やつらにぼこぼこにされて倒れていた私に、ヘイブン兄貴が手を差し伸べてくれたんだ。","ENG":"While I was on the ground after getting beat by them, that's when Mr. Haven reached out for me.","TWN":"我被那些小混混打到不醒人事的那天，是天堂大哥向我伸出手的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"그렇게 형님을 따라서 간 곳이…… 바로 위저드야.","JPN":"そうやって兄貴について行ったところが……ウィザードだったんだよ。","ENG":"And he took me to... Wizard.","TWN":"後來我跟著大哥來到的地方……就是巫師。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"위저드라고?","JPN":"ウィザードだって？","ENG":"Wizard?","TWN":"巫師？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"정말이야?","JPN":"本当か？","ENG":"Are you for real?","TWN":"真的嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"이른바 1기생이야. 형님이 나처럼 떠도는 녀석들을 데려다 보살펴 준 게 시초니까.","JPN":"いわゆる第1期生ってやつだね。私みたいに彷徨ってたやつらを集めて面倒見てくれたのが最初だから。","ENG":"Yup. 1st generation Wizard right here. It all started with Mr. Haven taking kids like me under his wing.","TWN":"我可是第一屆呢，大哥會收留無家可歸的孩子就是從我開始的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"불량배 놈들이 부러뜨린 손목을 위저드에서 치료받지 않았으면, 난 지금 스패너는커녕 연필도 못 쥘 거야.","JPN":"不良に折られた手首をウィザードで治療してもらわなかったら、今レンチはおろか鉛筆も握れてないはずよ。","ENG":"If Wizard didn't treat my broken wrists, I wouldn't have been able to hold a pencil, let alone a spanner.","TWN":"我被小混混弄斷的手腕要是沒在巫師接受治療，不要說板手，恐怕連鉛筆都拿不起來。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"어떻게든 치료비를 갚겠다니까, 형님이 뭐라고 하셨는지 알아?","JPN":"どうしても治療費を返すってきかない私に、兄貴はこう言ったの。","ENG":"So I told him that I'll do whatever it takes to repay him, and do you know what he said to me?","TWN":"我說我一定會想辦法付清醫藥費，但你知道大哥是怎麼說的嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"<color=#ffd34c>손목을 못 쓰면 카드 놀이도 같이 못 하잖아.</color> 였어.","JPN":"<color=#ffd34c>手首を使えないとカード遊びも一緒にできないじゃないか。</color>","ENG":"<color=#ffd34c>We won’t be able to play cards together if you have a broken wrist.</color>","TWN":"<color=#ffd34c>手腕不醫好就無法一起玩撲克牌的嘛</color>。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오, 좋은 아저씨네. 친구가 아파서 같이 못 놀면 나도 슬퍼.","JPN":"おお、いいおじさんだね。友達の具合が悪くて一緒に遊べないと私も悲しいよ。","ENG":"Ooh, so he's a good guy! I’d be sad, too, if a friend wouldn’t be able to play because of something like that.","TWN":"哇喔，很棒的叔叔欸！要是朋友受傷沒辦法和我一起玩，我也會很難過。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"하하. 맞아. 형님은 다 같이 즐기는 게 제일 중요하셨으니까.","JPN":"はは。そうだね。兄貴はみんなで楽しむのを一番大切にしてたから。","ENG":"Haha! You're right. It was important for Mr. Haven that everyone got to play.","TWN":"　"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"수아야, 저 이야기…….","JPN":"コトリちゃん、あの話……","ENG":"Skia, that story...","TWN":"蘇亞，她說的……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"검증되지 않은 허풍이야. 너무 귀담아들을 것 없어.","JPN":"検証されていない話だよ。深く気に留めなくてもいい。","ENG":"It's a fish story. Don't listen to it.","TWN":"是未經證實的，不必聽得太認真。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_HATE"}}}},{"id":"L43_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"위저드는 요즘 좀 어때?","JPN":"最近ウィザードはどう？","ENG":"How's Wizard these days?","TWN":"巫師最近如何？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"시간이 많이 지났다 보니 요즘 헤이븐 랜드로 오는 애들이랑은 자주 못 어울리거든.","JPN":"離れて結構経つから、最近ヘイブンランドにくる子たちとはあまり会ってないんだ。","ENG":"It's been a long time since I left, and I haven't had a chance to talk with the kids from there.","TWN":"有很長一段時間都無法常常和來天堂樂園的孩子相處呢。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그쪽이 하는 말이랑은 전혀 딴판이야.","JPN":"あんたの話とは全然違ってるよ。","ENG":"It's totally different from what you told us.","TWN":"跟你說的根本就是二回事！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"뭐?","JPN":"え？","ENG":"What?","TWN":"什麼事？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"우리가 아는 위저드는 애들을 약에 취하게 만들어서 이용해 먹던 마녀 소굴이야.","JPN":"私たちの知ってるウィザードは、子どもたちを薬漬けにして利用する魔女の巣だ。","ENG":"The Wizard we know is a witch's den where they drug up kids and exploit them.","TWN":"我們所認識的巫師，是一個利用藥物控制孩童的邪惡組織。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"나랑 도로시는 거기서 도망친 애들을 붙잡아 오는 역할이었고.","JPN":"ワタシとドロシーはそこから逃げ出した子たちを捕まえる役目だった。","ENG":"Dorothy's and my job there were to capture kids who tried to run away.","TWN":"而我和桃樂絲就是專門負責把那些逃跑的人抓回來。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"그게 무슨…….","JPN":"どういうこと……","ENG":"I don't understand...","TWN":"你那是什麼……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"NIGHTMARE_DREAM_SUMMER_NULL","text":{"KOREA":"나도 붙잡혔던 적이 있었어. 친구들 덕분에 나올 수 있었지만.","JPN":"私も捕まったことがあるよ。友達のおかげで出られたけど。","ENG":"I've been caught too, once. But I was able to get out because of my friends.","TWN":"我也被抓過，幸好有朋友的幫忙才能逃出來。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그럼 방금 이야기는 전부 거짓말이었던 거야? 거짓말쟁이는 나빠!","JPN":"じゃあ、今の話は全部嘘だったの？　嘘つきはダメ！","ENG":"Wait, then what she said just now was a lie? Lying is bad!","TWN":"那她剛才說的都是騙人的嗎？說謊是不好的行為！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그, 글린다. 지금 저 얘기가 전부 사실이야?","JPN":"ぐ、グリンダ。今の話、本当？","ENG":"G-Glinda. Is what you said all true?","TWN":"格…格琳達，她們說的是真的嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럼 넌 우리가 여태 장난으로 헤이븐 랜드를 불시착시키려는 줄 알았어?","JPN":"じゃあ、あんたは私たちがただのいたずらでヘイブンランドを不時着させようしてるとでも思ったの？","ENG":"Did you think we were trying to crash-land Havenland for fun?","TWN":"不然你以為我們說要讓天堂樂園迫降是鬧著玩的嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"그렇지는 않아. 그렇지는 않지만…….","JPN":"そうじゃない。そうじゃないけど……","ENG":"No, I didn't… But...","TWN":"不是的，只是……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"아니야. 헤이븐 형님이 아셨으면 그럴 리가 없어.","JPN":"変だよ。ヘイブン兄貴が知っていたらそうはならないはずなんだ。","ENG":"If Mr. Haven knew about it, he would never have let that happen.","TWN":"不，天堂大哥知道的話肯定不會有這種事的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"애초에 너희들의 장비도…….","JPN":"そもそもあんたたちの装備だって……","ENG":"Because even your equipment...","TWN":"原本你們的裝備也是……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"호란, 소식 들었어? 글쎄 위저드에 다리를 잃게 된 친구가 들어왔대.","JPN":"ホラン、聞いた？　ウィザードに足をなくした子が入ってきたらしいんだ。","ENG":"Horan, did you hear? A kid who lost her legs just came to Wizard.","TWN":"小蘭，你有聽到消息嗎？巫師來了個失去腿的孩子。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"친구들이랑 뛰어놀지 못하면 큰일이잖아? 의족이라도 만들어 주자.","JPN":"友達と走り回って遊べないなんて大変だよね？　義足でも作ってあげようよ。","ENG":"Won't it be such a shame if she can't run and play with her friends? Let's make her some prosthetic legs.","TWN":"要是不能再和朋友一起奔跑不是很可憐嗎？幫她做個義肢吧！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"그래! 기왕 만드는 김에 엄청 빠른 걸로!","JPN":"そうだ！　どうせ作るならめちゃくちゃ早いのを作ろう！","ENG":"Yeah! And while we're at it, let's make them go super fast!","TWN":"沒錯！既然要做，就做跑起來最快的！"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"참 기구하지. 친구는 식물 인간 상태래. 그런데 어떻게 마음 편히 놀겠어.","JPN":"まったく皮肉だよね。その子の友達は植物状態なんだって。そんなんじゃ気楽に遊べるわけがないよね。","ENG":"How terrible... Her friend is in a vegetative state. How will she be able to have fun without her?","TWN":"她真的很慘，聽說朋友還變成植物人，這樣是要怎麼安心地玩呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_NULL","text":{"KOREA":"무슨 신기술 같은 거 없을까? 조금만 도와 주면 어때?","JPN":"何か新しい技術はないかな？　ホラン、手伝ってくれない？","ENG":"Is there any new tech we could use? How about we help her out a little?","TWN":"有什麼最新技術嗎？幫她們點忙吧？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"……그렇게 형님이 던진 말로 제작에 착수했던 거야.","JPN":"……そんな兄貴の言葉で作り始めたんだ。","ENG":"...I started making them because Mr. Haven said so.","TWN":"……因為大哥那番話，我才著手製作。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"기술 근간은 퓨처 앳 워 프로젝트에서 유출된 데이터에 기반하고 있지만.","JPN":"技術の根幹はフューチャーアットウォープロジェクトから流出されたデータに基づいてるけど。","ENG":"Even if the technology was based on the Future-at-War Project's data that was leaked...","TWN":"只是是以天啟兵器計畫外洩的資料為基礎進行製作的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그것도 못 믿어. 위저드 인간들이 말하는 헤이븐은 피에 굶주린 인간 말종이었으니까.","JPN":"それも信じられない。ウィザードのやつらが話すヘイブンは血に飢えた人間のクズだったから。","ENG":"I don't trust that either. To the kids at Wizard, Haven is a sick, bloodthirsty scumbag.","TWN":"我不相信，巫師的人口裡所描述的大哥，是一個嗜血的人渣！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"위저드도 그렇고, 헤이븐 랜드도 그렇고. 대체 뭐가 진실인지 알 수가 없네.","JPN":"ウィザードもヘイブンランドも。いったい何が真実なのやら。","ENG":"Wizard and Haven... I can't tell what’s the truth.","TWN":"巫師和天堂樂園都是，根本分不清楚什麼才是真相。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"HAVEN_HAVEN_NULL_ROOT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HAVEN_HAVEN_NULL_ROOT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"……헤론.","JPN":"……ヘロンか。","ENG":"...Heron.","TWN":"……海倫。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그 마녀 같은 할멈?","JPN":"あの魔女みたいなババァ？","ENG":"You mean that old hag?","TWN":"你說那個老巫婆？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"다른 간부들이 헤이븐 랜드를 관리하는 동안, 위저드는 헤론이 총괄해 왔어.","JPN":"他の幹部がヘイブンランドを管理している間、ウィザードはヘロンが取りまとめてきた。","ENG":"While the other consiglieres managed Havenland, Heron was in charge of Wizard.","TWN":"其他幹部在管理天堂樂園時，巫師是海倫在負責的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"성격은 나빠도 헤이븐 형님과 가장 오랜 시간 함께해 온 사람이었으니까.","JPN":"性格は悪くてもヘイブン兄貴と一番長くやってきた人だったから。","ENG":"Even though she has a bad temper, she’s the one who has known Mr. Haven the longest out of all of us.","TWN":"雖然她人品不好，但再怎麼說也是跟著天堂大哥最久的人。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"하지만…… 대체 뭐 때문에…….","JPN":"でも……いったい何のために……","ENG":"But... Why would she...?","TWN":"但是……到底是什麼原因……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"이 문제는 그냥 넘어갈 수 없어. 간부로서 철저하게 확인해야 할 건이야.","JPN":"この問題はこのまま放っておけないね。幹部として徹底的に確認しないと。","ENG":"I can't let this slide. As a consigliere, I will get to the bottom of this.","TWN":"這個問題不能就這樣蒙混過去，身為幹部必須徹查到底。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"미안해. 만약 너희들의 이야기가 사실로 밝혀진다면…….","JPN":"ごめんね。もしあんたたちの話が本当なら……","ENG":"I'm sorry. If it turns out that all of you are right...","TWN":"抱歉，若調查發現你們所言屬實……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"무슨 수를 써서든 그 여자에게 잘못을 묻겠어.","JPN":"どんな手を使ってでもあの女に罪を認めさせてやる。","ENG":"I'll do everything in my power to give her what she deserves.","TWN":"那我一定會想盡辦法向她究責的！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"호란.","JPN":"ホラン。","ENG":"Horan.","TWN":"小蘭。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"휴스턴? 내 구역까지 무슨 일이야?","JPN":"ヒューストン？　私の区域まで何の用？","ENG":"Huston? What are you doing here?","TWN":"休士頓？你來我負責的區域做什麼？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"도전에 패배했다더군. 아이들은 어디로 갔지?","JPN":"挑戦に負けたらしいな。子どもたちはどこに行った？","ENG":"I heard you lost as well. Where are the kids?","TWN":"我聽說你吞下敗仗，那那些孩子們現在人呢？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"손가락 까딱 하면 알 수 있으면서 뭘 물어봐? 당연히 네 담당 구역으로 갔지.","JPN":"指一本あれば全部わかるでしょ？　もちろんあんたの担当区域に行ったよ。","ENG":"What are you asking me for? You already know where they are. They're headed towards your area now.","TWN":"你這不是明知故問嗎？當然是去你負責的區域囉。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"무슨 수를 써서라도 그 아이들을 막아야 됐어.","JPN":"どんな手を使ってでもあの子供たちを止めるべきだった。","ENG":"I have to stop them, by all means necessary.","TWN":"無論用什麼樣的方法，你都應該要阻止她們的。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"왜, 헤론이 그러라고 시켜서? 자기가 지상에서 하던 짓이 까발려질까 봐 무서워서?","JPN":"なんで？　ヘロンの指示？　自分が地上でやってたことがバレるから？","ENG":"Why? Did Heron put you up to this? Is she scared everyone found out what she did on the ground?","TWN":"為何？是海倫吩咐的嗎？她是怕她在地上的所作所為被揭發嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"호란, 내 말……","JPN":"ホラン、私の話を……","ENG":"Horan, listen...","TWN":"小蘭，你聽我……"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"내 말 끝까지 들어! 그 애들이 다 말해 줬다고! 내 손으로 만든 장비를 차고 온 애들이!","JPN":"よく聞きな！　あの子たちが全部話してくれたんだ！　私が作った装備を着けて来た子たちがね！","ENG":"No, you listen to me! Those kids told me everything! The very same kids I made equipment for!","TWN":"你先聽我說！她們全都告訴我了！就是那些穿著我親手製作的裝備的孩子們！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"얼치기들이 블랙 네트워크에 싸지른 루머라며? 헤이븐 형님이 모르실 리 없다며?","JPN":"間抜けがブラックネットワークにばらまいたデマだって言ったじゃない！　ヘイブン兄貴も知ってるはずだって！","ENG":"You said those were stupid rumors floating around on the Dark Network! That Mr. Haven knew all about it!","TWN":"酸民在黑色網路上放的假消息？天堂大哥不可能不知道？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"그 애들이 하는 말을 액면 그대로 믿나?","JPN":"あの子たちの言葉をそのまま信じるのか？","ENG":"Are you really taking their words at face value?","TWN":"那些孩子說的話你就信嗎？"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"믿냐고? 그래, 믿는다! 왜!","JPN":"信じるかって？　そうよ、信じるよ！　悪い！？","ENG":"So what if I am! Huh?!","TWN":"你問我信嗎？我信！怎樣！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RESORT_NPC_HAVEN_NULL","text":{"KOREA":"너야말로 어째서 헤론 그 망할 여자 편을 드는데! 형님 아니면 진즉 객사했을 주제에!","JPN":"あんたこそなんであのクソ女の肩を持つの！？　兄貴が居なかったらとっくに死んでたくせに！","ENG":"Why are you on Heron's side anyway?! You'd be long dead if it weren't for Mr. Haven!","TWN":"你怎麼會站在那個該死的海倫那邊！你忘記要不是大哥，你早就已經客死異鄉嗎！"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RESORT_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"내 대답은 간단해, 호란.","JPN":"私の答えは簡単だ、ホラン。","ENG":"My answer is simple, Horan.","TWN":"我的回答很簡單，小蘭。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"ENEMY_HAVEN_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"오직 헤이븐 형님을 위해서. 다른 이유는 없다.","JPN":"すべてはヘイブン兄貴のため。他の理由はない。","ENG":"It's all for Mr. Haven. There is no other reason.","TWN":"理由只有一個，一切都是為了天堂大哥。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ENEMY_HAVEN_NULL_C","face":"UNIT_IDLE"}}}}]`);export{e as default};